  if (w % 4 == 1 || w % 4 == 3) {
    x = (x * y) + (2 * z)
    z = x - z
  } else if (w % 3 == 0) {
    y = (x * x) + w
  }
  k = !k && (x > 0 || x < 0)
  console.log(x, y, z, w, k)
  w = w - 1
}
